INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.2.201','cb','cb.adi.2','ЧБ Ади 2.201',201,'হেন হরিধ্বনি হৈল সর্ব্ব-নদীয়ায় ।
ব্রহ্মা পূরিয়া ধ্বনি স্থান নাহি পায় ॥২০১॥','хена хари-дхвани хаила сарва-надӣйа̄йа
брахма̄н̣д̣а пӯрийа̄ дхвани стха̄на на̄хи па̄йа',NULL,NULL),('cb.adi.2.202','cb','cb.adi.2','ЧБ Ади 2.202',202,'অপূর্ব্ব শুনিয়া সব ভাগবতগণ ।
সবে বলে, “নিরন্তর হউক গ্রহণ” ॥২০২॥','апӯрва ш́унийа̄ саба бха̄гавата-ган̣а
сабе бале,—‘нирантара хаука грахан̣а’',NULL,NULL),('cb.adi.2.203','cb','cb.adi.2','ЧБ Ади 2.203',203,'সবে বলে,—“আজি বড় বাসিয়ে উল্লাস ।
হেন বুঝি, কিবা কৃষ্ণ করিলা প্রকাশ” ॥২০৩॥','сабе бале,—‘а̄джи бад̣а ва̄сийе улла̄са
хена буджхи, киба̄ кр̣ш̣н̣а карила̄ прака̄ш́а',NULL,NULL),('cb.adi.2.204','cb','cb.adi.2','ЧБ Ади 2.204',204,'গঙ্গাস্নানে চলিলা সকল ভক্তগণ ।
নিরবধি চতুর্দ্দিকে হরি-সঙ্কীর্ত্তন ॥২০৪॥','ган̇га̄-сна̄не чалила̄ сакала бхакта-ган̣а
ниравадхи чатур-дике хари-сан̇кӣртана',NULL,NULL),('cb.adi.2.205','cb','cb.adi.2','ЧБ Ади 2.205',205,'কিবা শিশু, বৃদ্ধ, নারী, সজ্জন, দুর্জ্জন ।
সবে ‘হরি’ ‘হরি’ বোলে দেখিয়া ‘গ্রহণ’ ॥২০৫॥','киба̄ ш́иш́у, вр̣ддха, на̄рӣ, саджджана, дурджана
сабе ‘хари’ ‘хари’ бале декхийа̄ ‘грахан̣а’',NULL,NULL),('cb.adi.2.206','cb','cb.adi.2','ЧБ Ади 2.206',206,'‘হরি বোল’ ‘হরি বোল’ সবে এই শুনি ।
সকল ব্রহ্মাণ্ডে ব্যাপিলেক হরিধ্বনি ॥২০৬॥','‘хари бола’ ‘хари бола’ сабе эи ш́уни
сакала-брахма̄н̣д̣е вйа̄пилека хари-дхвани',NULL,NULL),('cb.adi.2.207','cb','cb.adi.2','ЧБ Ади 2.207',207,'চতুর্দ্দিকে পুষ্পবৃষ্টি করে দেবগণ ।
‘জয়’-শব্দে দুন্দুভি বাজয়ে অনুক্ষণ ॥২০৭॥','чатур-дике пуш̣па-вр̣ш̣т̣и каре дева-ган̣а
‘джайа’-ш́абде дундубхи ба̄джайе анукш̣ан̣а',NULL,NULL),('cb.adi.2.208','cb','cb.adi.2','ЧБ Ади 2.208',208,'হেনই সময়ে সর্ব্বজগৎ-জীবন ।
অবতীর্ণ হইলেন শ্রীশচীনন্দন ॥২০৮॥','хенаи самайе сарва-джагат-джӣвана
аватӣрн̣а хаилена ш́рӣ-ш́ачӣ-нандана',NULL,NULL),('cb.adi.2.209','cb','cb.adi.2','ЧБ Ади 2.209',209,'রাহু-কবলে ইন্দু, পরকাশ নাম-সিন্ধু, কলি-মর্দ্দন বাজে বাণা ।
পহুঁ ভেল পরকাশ, ভুবন চতুর্দ্দশ, জয় জয় পড়িল ঘোষণা ॥২০৯॥','ра̄ху-кавале инду, парака̄ш́а на̄ма-синду, кали-мардана ба̄дже ба̄н̣а̄
пахун̇ бхела парака̄ш́а, бхувана чатур-даш́а, джайа джайа пад̣ила гхош̣ан̣а̄',NULL,NULL),('cb.adi.2.210','cb','cb.adi.2','ЧБ Ади 2.210',210,'দেখিতে গৌরাঙ্গচন্দ্র ।
নদীয়ার লোক- শোক সব নাশল,
দিনে দিনে বাড়ল আনন্দ ॥ধ্রু॥২১০॥','декхите гаура̄н̇га-чандра
надӣйа̄ра лока-ш́ока саба на̄ш́ала,
дине дине ба̄д̣ала а̄нанда',NULL,NULL),('cb.adi.2.211','cb','cb.adi.2','ЧБ Ади 2.211',211,'দুন্দুভি বাজে, শত শঙ্খ গাজে, বাজে বেণু-বিষাণ ।
শ্রীচৈতন্য-ঠাকুর, নিত্যানন্দ-প্রভু, বৃন্দাবনদাস গান ॥২১১॥','дундубхи ба̄дже, ш́ата ш́ан̇кха га̄дже, ба̄дже вен̣у-виш̣а̄н̣а
ш́рӣ-чаитанйа-т̣ха̄кура, нитйа̄нанда-прабху вр̣нда̄вана-да̄са га̄на',NULL,NULL),('cb.adi.2.212','cb','cb.adi.2','ЧБ Ади 2.212',212,'জিনিঞা রবি-কর, শ্রীঅঙ্গ-সুন্দর, নয়নে হেরই না পারি ।
আয়ত লোচন, ঈষৎ বঙ্কিম, উপমা নাহিক বিচারি ॥ধ্রু॥২১২॥','джинин̃а̄ рави-кара,	ш́рӣ-ан̇га-сундара, найане хераи на̄ па̄ри
а̄йата лочана, ӣш̣ат бан̇кима, упама̄ на̄хика вича̄ри',NULL,NULL),('cb.adi.2.213','cb','cb.adi.2','ЧБ Ади 2.213',213,'(আজু) বিজয়ে গৌরাঙ্গ, অবনী-মলে, চৌদিকে শুনিয়া উল্লাস ।
এক হরিধ্বনি, আ-ব্রহ্ম ভরি’ শুনি, গৌরাঙ্গচাঁদের পরকাশ ॥২১৩॥','(а̄джу) виджайе гаура̄н̇га, аванӣ-ман̣д̣але, чаудике ш́унийа̄ улла̄са
эка хари-дхвани, а̄-брахма бхари’ ш́уни, гаура̄н̇га-ча̄н̇дера парака̄ш́а',NULL,NULL),('cb.adi.2.214','cb','cb.adi.2','ЧБ Ади 2.214',214,'চন্দনে উজ্জ্বল, বক্ষ পরিসর, দোলয়ে তথি বনমাল ।
চাঁদ-সুশীতল, শ্রীমুখ-মণ্ডল, আ-জানু বাহু বিশাল ॥২১৪॥','чандане уджджвала, э вакш̣а парисара,
долайе татхи вана-ма̄ла
ча̄н̇да-суш́ӣтала, ш́рӣ-мукха-ман̣д̣ала, а̄-джа̄ну ба̄ху виш́а̄ла',NULL,NULL),('cb.adi.2.215','cb','cb.adi.2','ЧБ Ади 2.215',215,'দেখিয়া চৈতন্য, ভুবনে ধন্য-ধন্য, উঠয়ে জয়জয়-নাদ ।
কোই নাচত, কোই গায়ত, কলি হৈল হরিষে বিষাদ ॥২১৫॥','декхийа̄ чаитанйа, бхуване дханйа-дханйа, ут̣хайе джайа-джайа-на̄да
кои на̄чата,	кои га̄йата, кали хаила хариш̣е виш̣а̄да',NULL,NULL),('cb.adi.2.216','cb','cb.adi.2','ЧБ Ади 2.216',216,'চারি-বেদ-শির-মুকুট চৈতন্য, পামর মূঢ় নাহি জানে ।
শ্রীচৈতন্যচন্দ্র, নিতাই-ঠাকুর, বৃন্দাবনদাস গানে ॥২১৬॥','ча̄ри-веда-ш́ира мукут̣а чаитанйа па̄мара мӯд̣ха на̄хи джа̄не
ш́рӣ-чаитанйа-чандра, нита̄и-т̣ха̄кура, вр̣нда̄вана-да̄са га̄не',NULL,NULL),('cb.adi.2.217','cb','cb.adi.2','ЧБ Ади 2.217',217,'প্রকাশ হইলা গৌরচন্দ্র ।
দশ-দিকে উঠিল আনন্দ ॥ধ্রু॥২১৭॥','прака̄ш́а хаила̄ гаурачандра
даш́а-дике ут̣хила а̄нанда',NULL,NULL),('cb.adi.2.218','cb','cb.adi.2','ЧБ Ади 2.218',218,'রূপ কোটিমদন জিনিঞা ।
হাসে নিজ-কীর্ত্তন শুনিঞা ॥২১৮॥','рӯпа кот̣и-мадана джинин̃а̄
ха̄се ниджа-кӣртана ш́унин̃а̄',NULL,NULL),('cb.adi.2.219','cb','cb.adi.2','ЧБ Ади 2.219',219,'অতি-সুমধুর মুখ-আঁখি ।
মহারাজ-চিহ্ন সব দেখি ॥২১৯॥','ати-сумадхура мукха-а̄н̇кхи
маха̄ра̄джа-чихна саба декхи',NULL,NULL),('cb.adi.2.220','cb','cb.adi.2','ЧБ Ади 2.220',220,'শ্রীচরণে ধ্বজ-বজ্র শোভে ।
সব-অঙ্গে জগ-মন লোভে ॥২২০॥','ш́рӣ-чаран̣е дхваджа-ваджра ш́обхе
саба-ан̇ге джага-мана лобхе',NULL,NULL),('cb.adi.2.221','cb','cb.adi.2','ЧБ Ади 2.221',221,'দূরে গেল সকল আপদ ।
ব্যক্ত হইল সকল সম্পদ ॥২২১॥','дӯре гела сакала а̄пада',NULL,NULL),('cb.adi.2.222','cb','cb.adi.2','ЧБ Ади 2.222',222,'শ্রীচৈতন্য-নিত্যানন্দ জান ।
বৃন্দাবনদাস গুণ গান ॥২২২॥','ш́рӣ чаитанйа нитйа̄нанда джа̄на
вр̣нда̄вана да̄са гун̣а га̄на',NULL,NULL),('cb.adi.2.223','cb','cb.adi.2','ЧБ Ади 2.223',223,'চৈতন্য-অবতার, শুনিয়া দেবগণ, উঠিল পরম মঙ্গল রে ।
সকল-তাপ-হর, শ্রীমুখচন্দ্র দেখি’, আনন্দে হইলা বিহ্বল রে ॥ধ্রু॥২২৩॥','чаитанйа-авата̄ра, ш́унийа̄ дева-ган̣а, ут̣хила парама ман̇гала ре
сакала-та̄па-хара, ш́рӣ-мукха-чандра декхи’, а̄нанде хаила вихвала ре',NULL,NULL),('cb.adi.2.224','cb','cb.adi.2','ЧБ Ади 2.224',224,'অনন্ত, ব্রহ্মা, শিব, আদি করি’ যত দেব, সবেই নররূপ ধরি’ রে ।
গায়েন ‘হরি’ ‘হরি’, গ্রহণ-ছল করি’, লখিতে কেহ নাহি পারি রে ॥২২৪॥','ананта, брахма, ш́ива, а̄ди кари’ йата дева, сабеи нара-рӯпа дхари’ ре
га̄йена ‘хари’ ‘хари’, грахан̣а-чхала кари’, лакхите кеха на̄хи пари ре',NULL,NULL),('cb.adi.2.225','cb','cb.adi.2','ЧБ Ади 2.225',225,'দশ-দিকে ধায়,	লোক নদীয়ায়, বলিয়া উচ্চ ‘হরি’ ‘হরি’ রে ।
মানুষে দেবে মেলি’, একত্র হঞা কেলি, আনন্দে নবদ্বীপ পূরি রে ॥২২৫॥','даш́а-дике дха̄йа, лока надӣйа̄йа балийа̄ учча ‘хари’ ‘хари’ ре
ма̄нуш̣е деве мели’, экатра хан̃а̄ кели, а̄нанде навадвӣпа пӯри ре',NULL,NULL),('cb.adi.2.226','cb','cb.adi.2','ЧБ Ади 2.226',226,'শচীর অঙ্গনে, সকল দেবগণে, প্রণাম হইয়া পড়িলা রে ।
গ্রহণ-অন্ধকারে, লখিতে কেহ নারে, দুর্জ্ঞেয় চৈতন্যের খেলা রে ॥২২৬॥','ш́ачӣра ан̇гане, сакала дева-ган̣е, пран̣а̄ма хаийа̄ пад̣ила̄ ре
грахан̣а-андхака̄ре, лакхите кеха на̄ре, дурджн̃ейа чаитанйера кхела̄ ре',NULL,NULL),('cb.adi.2.227','cb','cb.adi.2','ЧБ Ади 2.227',227,'কেহ পড়ে স্তুতি, কাহারো হাতে ছাতি, কেহ চামর ঢুলায় রে ।
পরম-হরিষে, কেহ পুষ্প বরিষে, কেহ নাচে, গায়, বা’য় রে ॥২২৭॥','кеха пад̣е стути, ка̄ха̄ро ха̄те чха̄ти, ча̄мара д̣хула̄йа ре
парама-хариш̣е, кеха пуш̣па вариш̣е, кеха на̄че, га̄йа, ва̄’йа ре',NULL,NULL),('cb.adi.2.228','cb','cb.adi.2','ЧБ Ади 2.228',228,'সব-ভক্ত সঙ্গে করি’, আইলা গৌরহরি, পাষণ্ডী কিছুই না জানে রে ।
শ্রীকৃষ্ণচৈতন্য, প্রভু-নিত্যানন্দ, বৃন্দাবনদাস রস গান রে ॥২২৮॥','саба-бхакта сан̇ге кари’, а̄ила̄ гаурахари, па̄ш̣ан̣д̣ӣ кичхуи на̄ джа̄не ре
ш́рӣ кр̣ш̣н̣а-чаитанйа, прабху нитйа̄нанда, вр̣нда̄вана-да̄са раса га̄на ре',NULL,NULL),('cb.adi.2.229','cb','cb.adi.2','ЧБ Ади 2.229',229,'দুন্দুভি-ডিণ্ডিম- মঙ্গল-জয়ধ্বনি, গায় মধুর রসাল রে ।
বেদের অগোচর, আজি ভেটব, বিলম্বে নাহি আর কাল রে ॥ধ্রু॥২২৯॥','дундубхи-динд̣има-ман̇гала-джайа-дхвани, га̄йа мадхура раса̄ла ре
ведера агочара, а̄джи бхет̣ава, виламбе на̄хи а̄ра ка̄ла ре',NULL,NULL),('cb.adi.2.230','cb','cb.adi.2','ЧБ Ади 2.230',230,'আনন্দে ইন্দ্রপুর, মঙ্গল-কোলাহল, সাজ’ সাজ’ বলি’ সাজ’ রে ।
বহুত পুণ্য-ভাগ্যে, চৈতন্য-পরকাশ, পাওল নবদ্বীপ-মাঝে রে ॥২৩০॥','а̄нанде индрапура, ман̇гала-кола̄хала, са̄джа’ са̄джа’ бали’ са̄джа’ ре
бахута пун̣йа-бха̄гйе, чаитанйа-парака̄ш́а па̄ола навадвӣпа-ма̄джхе ре',NULL,NULL),('cb.adi.2.231','cb','cb.adi.2','ЧБ Ади 2.231',231,'অন্যোঽন্যে আলিঙ্গন, চুম্বন ঘন-ঘন, লাজ কেহ নাহি মানে রে ।
নদীয়া-পুরন্দর জনম-উল্লাসে, আপন-পর নাহি জানে রে ॥২৩১॥','анйо ’нйе а̄лин̇гана, чумбана гхана-гхана, ла̄джа кеха на̄хи ма̄не ре
надӣйа̄-пура̄н̣дара- джанама-улла̄се, а̄пана-пара на̄хи джа̄не ре',NULL,NULL),('cb.adi.2.232','cb','cb.adi.2','ЧБ Ади 2.232',232,'ঐছন কৌতুকে, আইলা নবদ্বীপে, চৌদিকে শুনি হরিনাম রে ।
পাইয়া গৌর-রস, বিহ্বল পরবশ, চৈতন্য-জয়জয় গান রে ॥২৩২॥','аичхана каутуке, а̄ила̄ навадвӣпе, чаудике ш́уни хари-на̄ма ре
па̄ийа̄ гаура-раса, вихвала параваш́а, чаитанйа-джайа-джайа га̄на ре',NULL,NULL),('cb.adi.2.233','cb','cb.adi.2','ЧБ Ади 2.233',233,'দেখিল শচী-গৃহে, গৌরাঙ্গ-সুন্দরে, একত্র যৈছে কোটিচান্দ রে ।
